function parseCSV(file) {
	return new Promise((resolve, reject) => {
		import_papaparse.default.parse(file, {
			header: true,
			skipEmptyLines: true,
			complete: (results) => {
				try {
					const parsed = results.data.map((row, idx) => ({
						row,
						lineNum: idx + 2
					})).filter(({ row }) => {
						return row.pergunta && row.pergunta.toLowerCase().trim() !== "pergunta";
					}).map(({ row, lineNum }) => {
						for (const field of [
							"pergunta",
							"opcao_a",
							"opcao_b",
							"opcao_c",
							"opcao_d",
							"resposta_correta"
						]) if (!row[field]) throw new Error(`Linha ${lineNum}: campo "${field}" vazio`);
						const resposta = String(row.resposta_correta).toUpperCase().trim();
						if (![
							"A",
							"B",
							"C",
							"D"
						].includes(resposta)) throw new Error(`Linha ${lineNum}: resposta inválida ("${resposta}"). Use apenas A, B, C ou D.`);
						return {
							question_text: String(row.pergunta).trim(),
							options: {
								A: String(row.opcao_a).trim(),
								B: String(row.opcao_b).trim(),
								C: String(row.opcao_c).trim(),
								D: String(row.opcao_d).trim()
							},
							correct_option: resposta
						};
					});
					if (parsed.length === 0) throw new Error("Nenhuma pergunta válida encontrada no CSV.");
					resolve(parsed);
				} catch (err) {
					reject(err);
				}
			},
			error: (error) => {
				reject(new Error(error.message));
			}
		});
	});
}
