			const { data: quiz, error: quizError } = await supabase.from("quizzes").select("id, status, pin").eq("pin", quizId.trim().toUpperCase()).single();
			if (quizError || !quiz) throw new Error("Código de partida inválido ou sala não existe.");
			if (quiz.status === "finished") throw new Error("Esta partida já encerrou.");
